class AppVersion extends DataClass implements Insertable<AppVersion> {
  final String id;
  final String version;
  final int buildNumber;
  final String? releaseNote;
  final String releaseDate;
  final bool isCurrent;
  final String createdAt;
  const AppVersion({
    required this.id,
    required this.version,
    required this.buildNumber,
    this.releaseNote,
    required this.releaseDate,
    required this.isCurrent,
    required this.createdAt,
  });
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<String>(id);
    map['version'] = Variable<String>(version);
    map['build_number'] = Variable<int>(buildNumber);
    if (!nullToAbsent || releaseNote != null) {
      map['release_note'] = Variable<String>(releaseNote);
    }
    map['release_date'] = Variable<String>(releaseDate);
    map['is_current'] = Variable<bool>(isCurrent);
    map['created_at'] = Variable<String>(createdAt);
    return map;
  }

  AppVersionsCompanion toCompanion(bool nullToAbsent) {
    return AppVersionsCompanion(
      id: Value(id),
      version: Value(version),
      buildNumber: Value(buildNumber),
      releaseNote: releaseNote == null && nullToAbsent
          ? const Value.absent()
          : Value(releaseNote),
      releaseDate: Value(releaseDate),
      isCurrent: Value(isCurrent),
      createdAt: Value(createdAt),
    );
  }

  factory AppVersion.fromJson(
    Map<String, dynamic> json, {
    ValueSerializer? serializer,
  }) {
    serializer ??= driftRuntimeOptions.defaultSerializer;
    return AppVersion(
