    map['sale_date'] = Variable<String>(saleDate);
    map['subtotal'] = Variable<int>(subtotal);
    map['discount_amount'] = Variable<int>(discountAmount);
    map['taxable_amount10'] = Variable<int>(taxableAmount10);
    map['taxable_amount8'] = Variable<int>(taxableAmount8);
    map['tax_amount10'] = Variable<int>(taxAmount10);
    map['tax_amount8'] = Variable<int>(taxAmount8);
    map['tax_exempt_amount'] = Variable<int>(taxExemptAmount);
