  final String paymentMethod;
  final String? receiptUrl;
  final String? notes;
  final String createdAt;
  const Expense({
    required this.id,
    required this.categoryId,
    this.staffId,
    required this.expenseDate,
    required this.amount,
    required this.taxType,
